import React, { Component } from "react";
import $ from "jquery";
import "./App.scss";
import Header from "./components/Header";
import Footer from "./components/Footer";
import About from "./components/About";
import Experience from "./components/Experience";
import Projects from "./components/Projects";
import Skills from "./components/Skills";
// import { motion, AnimatePresence } from "framer-motion";
import { motion } from "framer-motion";

class App extends Component {
  constructor(props) {
    super();
    this.state = {
      foo: "bar",
      resumeData: {},
      sharedData: {},
      activeLanguage: window.$primaryLanguage 
    };
  }

  applyPickedLanguage(pickedLanguage) {
    this.setState({ activeLanguage: pickedLanguage });
    document.documentElement.lang = pickedLanguage;

    var resumePath =
      document.documentElement.lang === window.$primaryLanguage
        ? `res_primaryLanguage.json`
        : `res_secondaryLanguage.json`;

    this.loadResumeFromPath(resumePath);
  }

  componentDidMount() {
    this.loadSharedData();
    this.applyPickedLanguage(window.$primaryLanguage);

    // Set default theme to light if not set to prevent "flash"
    if (!document.body.getAttribute("data-theme")) {
      document.body.setAttribute("data-theme", "light");
    }
  }

  loadResumeFromPath(path) {
    $.ajax({
      url: path,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ resumeData: data });
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error:", err);
      },
    });
  }

  loadSharedData() {
    $.ajax({
      url: `portfolio_shared_data.json`,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ sharedData: data });
        document.title = data.basic_info.name;
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error:", err);
      },
    });
  }

  render() {
    const isPrimary = this.state.activeLanguage === window.$primaryLanguage;
    const isSecondary = this.state.activeLanguage === window.$secondaryLanguage;

    return (
      <div style={{ background: "var(--body-background)", transition: "background 0.6s ease" }}>
        <Header sharedData={this.state.sharedData.basic_info} />

        {/* Language Switcher Section */}
        <div 
          className="col-md-12 mx-auto text-center language" 
          style={{ 
            padding: "20px 0", 
            background: "var(--body-background)",
            transition: "background 0.6s ease" 
          }}
        >
          {/* UK Flag */}
          <motion.div
            onClick={() => this.applyPickedLanguage(window.$primaryLanguage)}
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px",
              // Inline filter logic for immediate visual feedback
              filter: isPrimary ? "drop-shadow(0px 0px 8px rgba(174,148,79,0.4))" : "grayscale(0.8) opacity(0.5)"
            }}
            whileHover={{ scale: 1.2, filter: "grayscale(0) opacity(1)" }}
            whileTap={{ scale: 0.9 }}
            animate={{
               scale: isPrimary ? 1.2 : 1,
               opacity: isPrimary ? 1 : 0.6
            }}
            transition={{ type: "spring", stiffness: 300 }}
          >
            <span
              className="iconify"
              data-icon="twemoji-flag-for-flag-united-kingdom"
              data-inline="false"
              style={{ fontSize: "50px" }}
            ></span>
          </motion.div>

          {/* India Flag */}
          <motion.div
            onClick={() => this.applyPickedLanguage(window.$secondaryLanguage)}
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px",
              filter: isSecondary ? "drop-shadow(0px 0px 8px rgba(174,148,79,0.4))" : "grayscale(0.8) opacity(0.5)"
            }}
            whileHover={{ scale: 1.2, filter: "grayscale(0) opacity(1)" }}
            whileTap={{ scale: 0.9 }}
            animate={{
               scale: isSecondary ? 1.2 : 1,
               opacity: isSecondary ? 1 : 0.6
            }}
            transition={{ type: "spring", stiffness: 300 }}
          >
            <span
              className="iconify"
              data-icon="twemoji-flag-for-flag-india"
              data-inline="false"
              style={{ fontSize: "50px" }}
            ></span>
          </motion.div>
        </div>

        <About
          resumeBasicInfo={this.state.resumeData.basic_info}
          sharedBasicInfo={this.state.sharedData.basic_info}
        />
        <Projects
          resumeProjects={this.state.resumeData.projects}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Skills
          sharedSkills={this.state.sharedData.skills}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Experience
          resumeExperience={this.state.resumeData.experience}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Footer sharedBasicInfo={this.state.sharedData.basic_info} />
      </div>
    );
  }
}

export default App;
